def get_nested(d, *keys, default=None):
    cur = d
    for k in keys:
        if not isinstance(cur, dict) or k not in cur:
            return default
        cur = cur[k]
    return cur

d = {"profile": {"phone": "999"}}
print(get_nested(d, "profile", "phone"))
print(get_nested(d, "profile", "email", default="N/A"))
